import{_ as t,c as a,o as e,d as s}from"./app.262ed29e.js";var r="/assets/1TzO4y1T3l8-1.7bb3f2ab.jpg",_="/assets/MkgWrIjZGII.e6766113.jpg";const T='{"title":"Casual \u0410\u0442\u0435\u043B\u044C\u0435","description":"","frontmatter":{"title":"Casual \u0410\u0442\u0435\u043B\u044C\u0435","date":"2017-03-03","cover":"16908687_112820349245065_9030569301374926848_a.jpg"},"headers":[],"relativePath":"workshop/archive/casual-atelier/index.md"}',o={},p=s('<p><strong>Casual \u0410\u0442\u0435\u043B\u044C\u0435</strong> \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u043E\u0432\u044B\u0439 \u0444\u043E\u0440\u043C\u0430\u0442 \u0410\u0442\u0435\u043B\u044C\u0435.</p><p>\u041C\u044B \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E\xA0\u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u043C \u043F\u043E\u0448\u0438\u0432 \u0438 \u0440\u0435\u043C\u043E\u043D\u0442 \u043E\u0434\u0435\u0436\u0434\u044B, \u043C\u0435\u0445\u0430 \u0438 \u043A\u043E\u0436\u0438, \u0442\u0435\u043A\u0441\u0442\u0438\u043B\u044F \u0434\u043B\u044F \u0434\u043E\u043C\u0430 \u043F\u043E \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u043C \u0446\u0435\u043D\u0430\u043C. \u0422\u0430\u043A\u0436\u0435 \u0443 \u043D\u0430\u0441 \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0432\u043E\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0428\u0432\u0435\u0439\u043D\u044B\u043C \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433\u043E\u043C - \u044D\u0442\u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0438\u0439\u0442\u0438 \u0438 \u0448\u0438\u0442\u044C \u043D\u0430 \u043D\u0430\u0448\u0438\u0445 \u0448\u0432\u0435\u0439\u043D\u044B\u0445 \u043C\u0430\u0448\u0438\u043D\u043A\u0430\u0445 \u0441 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435\u043C \u0432\u0441\u0435\u0433\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0433\u043E \u0434\u043B\u044F \u0448\u0438\u0442\u044C\u044F \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F (\u043B\u0438\u043D\u0435\u0439\u043A\u0438, \u0441\u0430\u043D\u0442\u0438\u043C\u0435\u0442\u0440\u044B, \u043D\u043E\u0436\u043D\u0438\u0446\u044B, \u0431\u0443\u043B\u0430\u0432\u043A\u0438 \u0438 \u0434\u0440.).</p><p><strong>\u0428\u0432\u0435\u0439\u043D\u044B\u0439 \u043A\u043E\u0432\u043E\u0440\u043A\u0438\u043D\u0433</strong> - \u044D\u0442\u043E \u043F\u043E\u0447\u0430\u0441\u043E\u0432\u0430\u044F \u0430\u0440\u0435\u043D\u0434\u0430 \u0448\u0432\u0435\u0439\u043D\u044B\u0445 \u043C\u0430\u0448\u0438\u043D.</p><p>\u0412\u0430\u043C \u0431\u0443\u0434\u0443\u0442 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B:</p><ul><li>\u0431\u044B\u0442\u043E\u0432\u0430\u044F \u0448\u0432\u0435\u0439\u043D\u0430\u044F \u043C\u0430\u0448\u0438\u043D\u0430 Elna -\u0431\u044B\u0442\u043E\u0432\u043E\u0439 \u043E\u0432\u0435\u0440\u043B\u043E\u043A Janome -\u0431\u044B\u0442\u043E\u0432\u0430\u044F \u0440\u0430\u0441\u043F\u043E\u0448\u0438\u0432\u0430\u043B\u043A\u0430 Janome -\u0431\u043E\u043B\u044C\u0448\u043E\u0439 \u0440\u0430\u0441\u043A\u0440\u043E\u0439\u043D\u044B\u0439 \u0441\u0442\u043E\u043B</li><li>\u043D\u043E\u0436\u043D\u0438\u0446\u044B, \u0431\u0443\u043B\u0430\u0432\u043A\u0438, \u0438\u0433\u043B\u044B, \u0441\u0430\u043D\u0442\u0438\u043C\u0435\u0442\u0440\u044B, \u043B\u0438\u043D\u0435\u0439\u043A\u0438, \u043B\u0435\u043A\u0430\u043B\u0430, \u043C\u0435\u043B\u043A\u0438</li><li>\u043F\u043E\u043C\u043E\u0449\u044C \u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440\u0430</li></ul><p>\u0410\u0440\u0435\u043D\u0434\u0430 \u0432 \u0447\u0430\u0441 - 350 \u0440. \u041E\u0434\u0438\u043D \u0434\u0435\u043D\u044C \u0432 \u0431\u0443\u0434\u043D\u0438 - 1100 \u0440. \u041E\u0434\u0438\u043D \u0434\u0435\u043D\u044C \u0432 \u0432\u044B\u0445\u043E\u0434\u043D\u043E\u0439 - 1300 \u0440.</p><p>\u0423\u0441\u043F\u0435\u0439\u0442\u0435 \u043F\u043E\u0437\u0432\u043E\u043D\u0438\u0442\u044C \u0438 \u0437\u0430\u0431\u0440\u043E\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u0435\u0431\u0435 \u043C\u0435\u0441\u0442\u043E!</p><p><img src="'+r+'" alt=""><img src="'+_+'" alt=""></p>',8),i=[p];function l(n,c,d,m,g,u){return e(),a("div",null,i)}var h=t(o,[["render",l]]);export{T as __pageData,h as default};
